  body.innerHTML = `<div class="cp-loading">
    <div class="cp-loading-row"><div class="skeleton" style="width:70%;height:20px"></div></div>
    <div class="cp-loading-row"><div class="skeleton" style="width:50%;height:16px"></div></div>
