/* style.css — SIGNAL Trading Terminal Styles */

/* =========================================================================
   Design Tokens
   ========================================================================= */

:root {
  /* Backgrounds */
  --bg-primary: #0d1117;
  --bg-surface: #161b22;
  --bg-surface-2: #1c2128;
  --bg-surface-3: #21262d;
  --bg-hover: rgba(177, 186, 196, 0.06);
  --bg-active: rgba(177, 186, 196, 0.1);

  /* Borders */
  --border: #30363d;
  --border-muted: #21262d;
  --border-emphasis: #484f58;

  /* Text */
  --text-primary: #e6edf3;
  --text-secondary: #8b949e;
  --text-muted: #6e7681;
  --text-faint: #484f58;

  /* Semantic */
  --green: #3fb950;
  --green-bg: rgba(63, 185, 80, 0.1);
  --green-border: rgba(63, 185, 80, 0.3);
  --red: #f85149;
  --red-bg: rgba(248, 81, 73, 0.1);
  --red-border: rgba(248, 81, 73, 0.3);
  --yellow: #d29922;
  --yellow-bg: rgba(210, 153, 34, 0.1);
  --yellow-border: rgba(210, 153, 34, 0.3);
  --blue: #58a6ff;
  --blue-bg: rgba(88, 166, 255, 0.1);
  --blue-border: rgba(88, 166, 255, 0.3);

  /* Spacing (4px grid) */
  --sp-1: 4px;
  --sp-2: 8px;
  --sp-3: 12px;
  --sp-4: 16px;
  --sp-5: 20px;
  --sp-6: 24px;
  --sp-8: 32px;

  /* Radius */
  --radius-sm: 4px;
  --radius-md: 6px;
  --radius-lg: 8px;
  --radius-full: 9999px;

  /* Transitions */
  --ease-out: cubic-bezier(0.16, 1, 0.3, 1);
  --duration-fast: 120ms;
  --duration: 180ms;
  --duration-slow: 300ms;

  /* Sidebar */
  --sidebar-width: 260px;

  /* Header / Status bar */
  --header-height: 44px;
  --statusbar-height: 28px;
}

/* =========================================================================
   Dashboard Grid
   ========================================================================= */

.dashboard {
  display: grid;
  grid-template-columns: var(--sidebar-width) 1fr;
  grid-template-rows: var(--header-height) 1fr var(--statusbar-height);
  height: 100dvh;
  width: 100%;
}

/* =========================================================================
   Header
   ========================================================================= */

.header {
  grid-column: 1 / -1;
  grid-row: 1;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 var(--sp-4);
  background: var(--bg-surface);
  border-bottom: 1px solid var(--border);
  z-index: 20;
  gap: var(--sp-4);
}

.header-left {
  display: flex;
  align-items: center;
  gap: var(--sp-4);
}

.logo {
  font-family: 'JetBrains Mono', monospace;
  font-weight: 700;
  font-size: 16px;
  letter-spacing: 0.08em;
  color: var(--text-primary);
  display: flex;
  align-items: center;
  gap: var(--sp-2);
}

.logo-icon {
  width: 20px;
  height: 20px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.logo-icon svg {
  width: 20px;
  height: 20px;
}

.header-divider {
  width: 1px;
  height: 20px;
  background: var(--border);
}

.clock {
  font-family: 'JetBrains Mono', monospace;
  font-size: 12px;
  color: var(--text-secondary);
  font-variant-numeric: tabular-nums lining-nums;
  letter-spacing: 0.02em;
}

.header-right {
  display: flex;
  align-items: center;
  gap: var(--sp-3);
}

.header-stat {
  display: flex;
  align-items: center;
  gap: var(--sp-1);
  font-size: 11px;
  color: var(--text-secondary);
}

.header-stat .value {
  font-family: 'JetBrains Mono', monospace;
  font-variant-numeric: tabular-nums lining-nums;
  color: var(--text-primary);
  font-weight: 500;
}

/* Connection status */
.connection-status {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 11px;
  color: var(--text-secondary);
}

.status-dot {
  width: 7px;
  height: 7px;
  border-radius: 50%;
  background: var(--green);
  position: relative;
}

.status-dot.connected::after {
  content: '';
  position: absolute;
  inset: -3px;
  border-radius: 50%;
  background: var(--green);
  opacity: 0.4;
  animation: pulse 2s ease-in-out infinite;
}

@keyframes pulse {
  0%, 100% { transform: scale(1); opacity: 0.4; }
  50% { transform: scale(1.8); opacity: 0; }
}

.status-dot.disconnected {
  background: var(--red);
}

.status-dot.disconnected::after {
  display: none;
}

.btn-header {
  display: flex;
  align-items: center;
  gap: var(--sp-1);
  padding: 4px 10px;
  font-size: 11px;
  font-weight: 500;
  color: var(--text-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius-md);
  background: var(--bg-surface-2);
  transition: all var(--duration) var(--ease-out);
  white-space: nowrap;
}

.btn-header:hover {
  background: var(--bg-surface-3);
  color: var(--text-primary);
  border-color: var(--border-emphasis);
}

.btn-header:active {
  transform: scale(0.97);
}

.btn-header svg {
  width: 14px;
  height: 14px;
  flex-shrink: 0;
}

/* Mobile hamburger */
.hamburger-btn {
  display: none;
  align-items: center;
  justify-content: center;
  width: 32px;
  height: 32px;
  border-radius: var(--radius-md);
  color: var(--text-secondary);
  transition: all var(--duration) var(--ease-out);
}

.hamburger-btn:hover {
  background: var(--bg-hover);
  color: var(--text-primary);
}

.hamburger-btn svg {
  width: 18px;
  height: 18px;
}

/* =========================================================================
   Sidebar
   ========================================================================= */

.sidebar {
  grid-column: 1;
  grid-row: 2 / 4;
  background: var(--bg-surface);
  border-right: 1px solid var(--border);
  overflow-y: auto;
  overscroll-behavior: contain;
  padding: var(--sp-3);
  display: flex;
  flex-direction: column;
  gap: var(--sp-4);
}

.sidebar-section {
  display: flex;
  flex-direction: column;
  gap: var(--sp-2);
}

.sidebar-label {
  font-size: 10px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: var(--text-muted);
  padding: 0 var(--sp-1);
}

/* Search input */
.search-wrap {
  position: relative;
}

.search-wrap svg {
  position: absolute;
  left: 8px;
  top: 50%;
  transform: translateY(-50%);
  width: 14px;
  height: 14px;
  color: var(--text-muted);
  pointer-events: none;
}

.search-input {
  width: 100%;
  padding: 6px 8px 6px 28px;
  font-size: 12px;
  color: var(--text-primary);
  background: var(--bg-primary);
  border: 1px solid var(--border);
  border-radius: var(--radius-md);
  transition: border-color var(--duration) var(--ease-out);
}

.search-input::placeholder {
  color: var(--text-muted);
}

.search-input:focus {
  outline: none;
  border-color: var(--blue);
  box-shadow: 0 0 0 3px var(--blue-bg);
}

.search-kbd {
  position: absolute;
  right: 8px;
  top: 50%;
  transform: translateY(-50%);
  font-family: 'JetBrains Mono', monospace;
  font-size: 9px;
  color: var(--text-muted);
  background: var(--bg-surface-2);
  padding: 1px 5px;
  border-radius: 3px;
  border: 1px solid var(--border);
  pointer-events: none;
}

/* Filter buttons */
.filter-group {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.filter-btn {
  display: flex;
  align-items: center;
  gap: var(--sp-2);
  padding: 5px 8px;
  font-size: 12px;
  color: var(--text-secondary);
  border-radius: var(--radius-sm);
  transition: all var(--duration-fast) var(--ease-out);
  cursor: pointer;
  width: 100%;
  text-align: left;
}

.filter-btn:hover {
  background: var(--bg-hover);
  color: var(--text-primary);
}

.filter-btn:active {
  background: var(--bg-active);
}

.filter-btn.active {
  background: var(--bg-active);
  color: var(--text-primary);
  font-weight: 500;
}

.filter-btn .dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  flex-shrink: 0;
}

.filter-btn .count {
  margin-left: auto;
  font-family: 'JetBrains Mono', monospace;
  font-variant-numeric: tabular-nums lining-nums;
  font-size: 10px;
  color: var(--text-muted);
}

.filter-btn .kbd {
  margin-left: auto;
  font-family: 'JetBrains Mono', monospace;
  font-size: 9px;
  color: var(--text-faint);
  background: var(--bg-surface-2);
  padding: 0 4px;
  border-radius: 2px;
  border: 1px solid var(--border-muted);
}

/* Source checkboxes */
.source-list {
  display: flex;
  flex-direction: column;
  gap: 1px;
  max-height: 280px;
  overflow-y: auto;
  overscroll-behavior: contain;
}

.source-item {
  display: flex;
  align-items: center;
  gap: var(--sp-2);
  padding: 4px 8px;
  font-size: 11px;
  color: var(--text-secondary);
  border-radius: var(--radius-sm);
  cursor: pointer;
  transition: all var(--duration-fast) var(--ease-out);
  user-select: none;
}

.source-item:hover {
  background: var(--bg-hover);
}

.source-item:active {
  background: var(--bg-active);
}

.source-item input[type="checkbox"] {
  appearance: none;
  -webkit-appearance: none;
  width: 14px;
  height: 14px;
  border: 1px solid var(--border-emphasis);
  border-radius: 3px;
  background: var(--bg-primary);
  cursor: pointer;
  flex-shrink: 0;
  transition: all var(--duration-fast);
  position: relative;
}

.source-item input[type="checkbox"]:checked {
  background: var(--blue);
  border-color: var(--blue);
}

.source-item input[type="checkbox"]:checked::after {
  content: '';
  position: absolute;
  left: 4px;
  top: 1px;
  width: 4px;
  height: 8px;
  border: solid #fff;
  border-width: 0 1.5px 1.5px 0;
  transform: rotate(45deg);
}

.source-item .source-count {
  margin-left: auto;
  font-family: 'JetBrains Mono', monospace;
  font-variant-numeric: tabular-nums lining-nums;
  font-size: 10px;
  color: var(--text-muted);
}

/* Refresh interval */
.interval-select {
  width: 100%;
  padding: 5px 8px;
  font-size: 12px;
  color: var(--text-primary);
  background: var(--bg-primary);
  border: 1px solid var(--border);
  border-radius: var(--radius-md);
  cursor: pointer;
}

.interval-select:focus {
  outline: none;
  border-color: var(--blue);
}

/* Date range filter */
.date-range-wrap {
  display: flex;
  flex-direction: column;
  gap: var(--sp-2);
}

.date-range-row {
  display: flex;
  align-items: center;
  gap: var(--sp-2);
}

.date-range-label {
  font-size: 11px;
  color: var(--text-muted);
  min-width: 34px;
  flex-shrink: 0;
}

.date-input {
  flex: 1;
  width: 100%;
  padding: 5px 8px;
  font-size: 12px;
  color: var(--text-primary);
  background: var(--bg-primary);
  border: 1px solid var(--border);
  border-radius: var(--radius-md);
  transition: border-color var(--duration) var(--ease-out);
  color-scheme: dark;
}

.date-input:focus {
  outline: none;
  border-color: var(--blue);
  box-shadow: 0 0 0 3px var(--blue-bg);
}

.date-input::-webkit-calendar-picker-indicator {
  filter: invert(0.7);
  cursor: pointer;
}

.btn-clear-dates {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: var(--sp-1);
  padding: 4px 8px;
  font-size: 11px;
  color: var(--text-muted);
  border-radius: var(--radius-sm);
  transition: all var(--duration-fast) var(--ease-out);
  cursor: pointer;
  width: 100%;
}

.btn-clear-dates:hover {
  background: var(--bg-hover);
  color: var(--text-secondary);
}

.btn-clear-dates:active {
  background: var(--bg-active);
}

/* =========================================================================
   Main Content Area
   ========================================================================= */

.main {
  grid-column: 2;
  grid-row: 2;
  overflow-y: auto;
  overscroll-behavior: contain;
  background: var(--bg-primary);
}

/* News table */
.news-table {
  width: 100%;
  font-size: 12px;
}

.news-table thead {
  position: sticky;
  top: 0;
  z-index: 5;
  background: var(--bg-surface);
}

.news-table th {
  padding: 6px 12px;
  text-align: left;
  font-size: 10px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  color: var(--text-muted);
  border-bottom: 1px solid var(--border);
  white-space: nowrap;
  user-select: none;
  position: relative;
  overflow: hidden;
  text-overflow: ellipsis;
}

.news-table th.col-time { width: 70px; }
.news-table th.col-sentiment { width: 80px; }
.news-table th.col-source { width: 120px; }
.news-table th.col-headline { }
.news-table th.col-summary { width: 25%; min-width: 120px; }
.news-table th.col-ticker { width: 160px; }
.news-table th.col-confidence { width: 90px; }
.news-table th.col-risk { width: 90px; }
.news-table th.col-tradeable { width: 80px; }

/* Column resize handle */
.col-resize-handle {
  position: absolute;
  top: 0;
  right: 0;
  width: 6px;
  height: 100%;
  cursor: col-resize;
  background: transparent;
  z-index: 2;
}
.col-resize-handle:hover,
.col-resize-handle.active {
  background: var(--blue);
}

.news-table td {
  padding: 6px 12px;
  border-bottom: 1px solid var(--border-muted);
  vertical-align: top;
  overflow: hidden;
  text-overflow: ellipsis;
}

.news-table tbody tr {
  transition: background var(--duration-fast);
}

.news-table tbody tr:hover {
  background: var(--bg-hover);
}

/* Time column */
.cell-time {
  font-family: 'JetBrains Mono', monospace;
  font-variant-numeric: tabular-nums lining-nums;
  font-size: 11px;
  color: var(--text-muted);
  white-space: nowrap;
}

/* Sentiment badge */
.sentiment-badge {
  display: inline-flex;
  align-items: center;
  gap: 5px;
  padding: 2px 8px;
  border-radius: var(--radius-full);
  font-size: 10px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  white-space: nowrap;
}

.sentiment-badge.bullish {
  color: var(--green);
  background: var(--green-bg);
}

.sentiment-badge.bearish {
  color: var(--red);
  background: var(--red-bg);
}

.sentiment-badge.neutral {
  color: var(--yellow);
  background: var(--yellow-bg);
}

.sentiment-dot {
  width: 6px;
  height: 6px;
  border-radius: 50%;
}

.bullish .sentiment-dot { background: var(--green); }
.bearish .sentiment-dot { background: var(--red); }
.neutral .sentiment-dot { background: var(--yellow); }

/* Source tag */
.source-tag {
  display: inline-block;
  padding: 2px 6px;
  font-size: 10px;
  font-weight: 500;
  border-radius: var(--radius-sm);
  background: var(--bg-surface-2);
  color: var(--text-secondary);
  border: 1px solid var(--border-muted);
  white-space: nowrap;
  max-width: 110px;
  overflow: hidden;
  text-overflow: ellipsis;
}

/* Headline */
.cell-headline {
  font-weight: 500;
  color: var(--text-primary);
  line-height: 1.4;
}

.cell-headline a {
  color: var(--text-primary);
  transition: color var(--duration-fast);
}

.cell-headline a:hover {
  color: var(--blue);
}

/* Summary */
.cell-summary {
  color: var(--text-secondary);
  font-size: 11px;
  line-height: 1.4;
  max-width: 400px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

/* Ticker */
.cell-ticker {
  white-space: nowrap;
}

.ticker-symbol {
  display: inline-block;
  padding: 1px 6px;
  background: var(--blue-bg);
  border: 1px solid var(--blue-border);
  border-radius: var(--radius-sm);
  font-family: 'JetBrains Mono', monospace;
  font-size: 10px;
  font-weight: 600;
  color: var(--blue);
}

.ticker-badge {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 2px 8px;
  background: var(--blue-bg);
  border: 1px solid var(--blue-border);
  border-radius: var(--radius-sm);
  font-family: 'JetBrains Mono', monospace;
  font-size: 10px;
  font-weight: 600;
  color: var(--blue);
  cursor: pointer;
  white-space: nowrap;
  transition: background 0.15s;
}

.ticker-badge:hover {
  background: rgba(88, 166, 255, 0.18);
}

.ticker-price {
  font-weight: 500;
  font-size: 10px;
}

.ticker-price.price-up {
  color: var(--green);
}

.ticker-price.price-down {
  color: var(--red);
}

.ticker-price.price-flat {
  color: var(--text-secondary);
}

.ticker-change {
  font-size: 9px;
  opacity: 0.85;
}

/* Confidence */
.cell-confidence {
  font-family: 'JetBrains Mono', monospace;
  font-variant-numeric: tabular-nums lining-nums;
  font-size: 11px;
  color: var(--text-secondary);
  white-space: nowrap;
}

/* Risk Level */
.cell-risk {
  white-space: nowrap;
}

.risk-badge {
  display: inline-block;
  padding: 2px 6px;
  border-radius: var(--radius-sm);
  font-family: 'JetBrains Mono', monospace;
  font-size: 10px;
  font-weight: 600;
}

.risk-badge.green {
  color: var(--green);
  background: var(--green-bg);
}

.risk-badge.yellow {
  color: var(--yellow);
  background: var(--yellow-bg);
}

.risk-badge.red {
  color: var(--red);
  background: var(--red-bg);
}

/* Tradeable */
.cell-tradeable {
  white-space: nowrap;
}

.tradeable-badge {
  display: inline-block;
  padding: 2px 6px;
  border-radius: var(--radius-sm);
  font-family: 'JetBrains Mono', monospace;
  font-size: 10px;
  font-weight: 600;
}

.tradeable-badge.yes {
  color: var(--green);
  background: var(--green-bg);
}

.tradeable-badge.no {
  color: var(--red);
  background: var(--red-bg);
}

/* Cell dash (empty value) */
.cell-dash {
  color: var(--text-faint);
}

/* NEW badge */
.badge-new {
  display: inline-flex;
  align-items: center;
  padding: 1px 5px;
  font-family: 'JetBrains Mono', monospace;
  font-size: 9px;
  font-weight: 700;
  color: var(--green);
  background: var(--green-bg);
  border: 1px solid var(--green-border);
  border-radius: var(--radius-sm);
  margin-left: var(--sp-2);
  animation: badge-flash 1s ease-out;
  letter-spacing: 0.05em;
}

.badge-dup {
  display: inline-flex;
  align-items: center;
  padding: 1px 5px;
  font-family: 'JetBrains Mono', monospace;
  font-size: 9px;
  font-weight: 700;
  color: var(--yellow);
  background: rgba(210, 153, 34, 0.1);
  border: 1px solid rgba(210, 153, 34, 0.3);
  border-radius: var(--radius-sm);
  margin-left: var(--sp-2);
  letter-spacing: 0.05em;
  opacity: 0.8;
}

/* New row animation */
.news-row-new {
  animation: row-enter 0.6s var(--ease-out);
}

@keyframes row-enter {
  0% {
    opacity: 0;
    background: var(--green-bg);
    box-shadow: inset 2px 0 0 var(--green);
  }
  60% {
    background: rgba(63, 185, 80, 0.04);
    box-shadow: inset 2px 0 0 rgba(63, 185, 80, 0.3);
  }
  100% {
    opacity: 1;
    background: transparent;
    box-shadow: none;
  }
}

@keyframes badge-flash {
  0% { opacity: 0; transform: scale(0.8); }
  50% { transform: scale(1.1); }
  100% { opacity: 1; transform: scale(1); }
}

/* =========================================================================
   Status Bar
   ========================================================================= */

.statusbar {
  grid-column: 1 / -1;
  grid-row: 3;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 var(--sp-4);
  background: var(--bg-surface);
  border-top: 1px solid var(--border);
  font-size: 11px;
  color: var(--text-muted);
  z-index: 20;
  gap: var(--sp-4);
}

.statusbar-left, .statusbar-right {
  display: flex;
  align-items: center;
  gap: var(--sp-4);
}

.statusbar-item {
  display: flex;
  align-items: center;
  gap: var(--sp-1);
  white-space: nowrap;
}

.statusbar-item .value {
  font-family: 'JetBrains Mono', monospace;
  font-variant-numeric: tabular-nums lining-nums;
  color: var(--text-secondary);
}

.site-links {
  gap: var(--sp-3);
}

.site-links a {
  color: var(--text-muted);
  text-decoration: none;
  font-size: 10px;
}

.site-links a:hover {
  color: var(--text-secondary);
}

.statusbar .api-url {
  font-family: 'JetBrains Mono', monospace;
  font-size: 10px;
  color: var(--text-faint);
  cursor: pointer;
  transition: color var(--duration-fast);
}

.statusbar .api-url:hover {
  color: var(--blue);
}

/* =========================================================================
   Loading & Empty States
   ========================================================================= */

.loading-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: var(--sp-8);
  color: var(--text-muted);
  gap: var(--sp-3);
}

.loading-spinner {
  width: 24px;
  height: 24px;
  border: 2px solid var(--border);
  border-top-color: var(--blue);
  border-radius: 50%;
  animation: spin 0.8s linear infinite;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

.empty-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: var(--sp-8) var(--sp-4);
  color: var(--text-muted);
  text-align: center;
  gap: var(--sp-2);
}

.empty-state .icon {
  font-size: 32px;
  opacity: 0.3;
  margin-bottom: var(--sp-2);
}

/* Skeleton rows */
.skeleton-row {
  display: flex;
  align-items: center;
  padding: 8px 12px;
  gap: 12px;
  border-bottom: 1px solid var(--border-muted);
}

.skeleton-block {
  height: 12px;
  background: var(--bg-surface-2);
  border-radius: 3px;
  animation: skeleton-pulse 1.5s ease-in-out infinite;
}

@keyframes skeleton-pulse {
  0%, 100% { opacity: 0.4; }
  50% { opacity: 0.8; }
}

/* =========================================================================
   Modal (API Docs)
   ========================================================================= */

.modal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.7);
  backdrop-filter: blur(4px);
  z-index: 100;
  display: flex;
  align-items: center;
  justify-content: center;
  opacity: 0;
  pointer-events: none;
  transition: opacity var(--duration-slow) var(--ease-out);
}

.modal-overlay.open {
  opacity: 1;
  pointer-events: auto;
}

.modal {
  background: var(--bg-surface);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  width: min(640px, 90vw);
  max-height: 80vh;
  overflow-y: auto;
  overscroll-behavior: contain;
  box-shadow: 0 24px 48px rgba(0, 0, 0, 0.4);
  transform: scale(0.95) translateY(10px);
  transition: transform var(--duration-slow) var(--ease-out);
}

.modal-overlay.open .modal {
  transform: scale(1) translateY(0);
}

.modal-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--sp-4);
  border-bottom: 1px solid var(--border);
}

.modal-header h2 {
  font-family: 'JetBrains Mono', monospace;
  font-size: 14px;
  font-weight: 600;
  color: var(--text-primary);
}

.modal-close {
  width: 28px;
  height: 28px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: var(--radius-sm);
  color: var(--text-muted);
  transition: all var(--duration-fast);
}

.modal-close:hover {
  background: var(--bg-hover);
  color: var(--text-primary);
}

.modal-body {
  padding: var(--sp-4);
}

.api-endpoint {
  margin-bottom: var(--sp-4);
  border: 1px solid var(--border-muted);
  border-radius: var(--radius-md);
  overflow: hidden;
}

.api-endpoint-header {
  display: flex;
  align-items: center;
  gap: var(--sp-2);
  padding: var(--sp-2) var(--sp-3);
  background: var(--bg-surface-2);
  border-bottom: 1px solid var(--border-muted);
}

.api-method {
  font-family: 'JetBrains Mono', monospace;
  font-size: 11px;
  font-weight: 700;
  padding: 2px 6px;
  border-radius: 3px;
}

.api-method.get {
  color: var(--green);
  background: var(--green-bg);
}

.api-method.post {
  color: var(--blue);
  background: var(--blue-bg);
}

.api-path {
  font-family: 'JetBrains Mono', monospace;
  font-size: 12px;
  color: var(--text-primary);
}

.api-endpoint-body {
  padding: var(--sp-3);
  font-size: 12px;
  color: var(--text-secondary);
  line-height: 1.6;
}

.api-endpoint-body p {
  margin-bottom: var(--sp-2);
}

.api-params {
  margin: var(--sp-2) 0;
}

.api-params dt {
  font-family: 'JetBrains Mono', monospace;
  font-size: 11px;
  color: var(--blue);
  margin-top: var(--sp-1);
}

.api-params dd {
  font-size: 11px;
  color: var(--text-muted);
  padding-left: var(--sp-4);
}

.api-curl {
  font-family: 'JetBrains Mono', monospace;
  font-size: 11px;
  background: var(--bg-primary);
  padding: var(--sp-2) var(--sp-3);
  border-radius: var(--radius-sm);
  color: var(--text-secondary);
  overflow-x: auto;
  white-space: pre;
  margin-top: var(--sp-2);
  border: 1px solid var(--border-muted);
}

/* =========================================================================
   Detail Modal (Ticker Recommendation)
   ========================================================================= */

.detail-modal {
  width: min(520px, 90vw);
}

/* Make news rows clickable */
.news-table tbody tr[data-id] {
  cursor: pointer;
}

.news-table tbody tr[data-id]:hover {
  background: var(--bg-hover);
}

/* Article context */
.detail-article {
  margin-bottom: var(--sp-4);
  padding-bottom: var(--sp-4);
  border-bottom: 1px solid var(--border-muted);
}

.detail-headline {
  font-size: 14px;
  font-weight: 600;
  color: var(--text-primary);
  line-height: 1.5;
  margin: 0 0 var(--sp-2);
}

.detail-meta {
  display: flex;
  align-items: center;
  gap: var(--sp-2);
  font-size: 12px;
  color: var(--text-muted);
}

.detail-time {
  font-family: 'JetBrains Mono', monospace;
  font-size: 11px;
}

/* Ticker header */
.detail-ticker-header {
  display: flex;
  align-items: center;
  gap: var(--sp-3);
  margin-bottom: var(--sp-4);
}

.detail-ticker-symbol {
  font-family: 'JetBrains Mono', monospace;
  font-size: 28px;
  font-weight: 700;
  color: var(--blue);
  letter-spacing: 1px;
}

.detail-asset-type {
  font-family: 'JetBrains Mono', monospace;
  font-size: 11px;
  color: var(--text-muted);
  padding: 2px 8px;
  background: var(--bg-surface-2);
  border: 1px solid var(--border-muted);
  border-radius: var(--radius-sm);
  text-transform: uppercase;
}

/* Metrics grid */
.detail-metrics {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: var(--sp-3);
  margin-bottom: var(--sp-4);
}

.detail-metric {
  padding: var(--sp-3);
  background: var(--bg-surface-2);
  border: 1px solid var(--border-muted);
  border-radius: var(--radius-md);
}

.detail-metric-label {
  font-size: 10px;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-bottom: var(--sp-1);
}

.detail-metric-value {
  font-size: 14px;
  font-weight: 600;
  color: var(--text-primary);
  display: flex;
  align-items: center;
  gap: var(--sp-2);
}

.detail-metric-sub {
  font-size: 12px;
  font-weight: 400;
  color: var(--text-secondary);
}

.detail-confidence {
  font-family: 'JetBrains Mono', monospace;
  font-size: 20px;
  color: var(--blue);
}

/* Risk level colors */
.detail-risk {
  font-family: 'JetBrains Mono', monospace;
  font-size: 12px;
  font-weight: 600;
  padding: 2px 8px;
  border-radius: var(--radius-sm);
}

.detail-risk.green {
  color: var(--green);
  background: var(--green-bg);
}

.detail-risk.yellow {
  color: var(--yellow);
  background: var(--yellow-bg);
}

.detail-risk.red {
  color: var(--red);
  background: var(--red-bg);
}

/* Tradeable badge */
.detail-tradeable {
  font-family: 'JetBrains Mono', monospace;
  font-size: 12px;
  font-weight: 600;
  padding: 2px 8px;
  border-radius: var(--radius-sm);
}

.detail-tradeable.yes {
  color: var(--green);
  background: var(--green-bg);
}

.detail-tradeable.no {
  color: var(--red);
  background: var(--red-bg);
}

/* Reasoning section */
.detail-reasoning {
  border-top: 1px solid var(--border-muted);
  padding-top: var(--sp-3);
}

.detail-reasoning-label {
  font-size: 10px;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-bottom: var(--sp-2);
}

.detail-reasoning-text {
  font-size: 13px;
  color: var(--text-secondary);
  line-height: 1.7;
  max-height: 200px;
  overflow-y: auto;
  overscroll-behavior: contain;
  white-space: pre-wrap;
}

/* Upgrade prompt (non-Max users) */
.detail-upgrade {
  text-align: center;
  padding: var(--sp-6) var(--sp-4);
}

.detail-upgrade-icon {
  font-size: 32px;
  color: var(--text-muted);
  margin-bottom: var(--sp-3);
}

.detail-upgrade h4 {
  font-size: 16px;
  font-weight: 600;
  color: var(--text-primary);
  margin: 0 0 var(--sp-2);
}

.detail-upgrade p {
  font-size: 13px;
  color: var(--text-secondary);
  line-height: 1.6;
  margin: 0 0 var(--sp-4);
}

.detail-upgrade-btn {
  display: inline-block;
  padding: 10px 24px;
  background: #238636;
  color: #fff;
  border-radius: var(--radius-md);
  text-decoration: none;
  font-weight: 600;
  font-size: 14px;
  transition: background var(--duration-fast);
}

.detail-upgrade-btn:hover {
  background: #2ea043;
}

/* Pending / no recommendation state */
.detail-pending {
  text-align: center;
  padding: var(--sp-6) var(--sp-4);
}

.detail-pending-icon {
  font-size: 32px;
  color: var(--text-muted);
  margin-bottom: var(--sp-3);
}

.detail-pending p {
  font-size: 14px;
  color: var(--text-secondary);
  margin: 0 0 var(--sp-1);
}

.detail-pending span {
  font-size: 12px;
  color: var(--text-muted);
}

/* =========================================================================
   Keyboard shortcuts overlay
   ========================================================================= */

.shortcuts-hint {
  font-size: 10px;
  color: var(--text-faint);
  padding: var(--sp-2);
  text-align: center;
  border-top: 1px solid var(--border-muted);
  margin-top: auto;
}

.shortcuts-hint kbd {
  font-family: 'JetBrains Mono', monospace;
  font-size: 9px;
  padding: 1px 4px;
  background: var(--bg-surface-2);
  border: 1px solid var(--border);
  border-radius: 3px;
  margin: 0 2px;
}

/* =========================================================================
   Performance
   ========================================================================= */

.news-table tbody tr {
  content-visibility: auto;
  contain-intrinsic-size: 0 32px;
}

/* =========================================================================
   Responsive
   ========================================================================= */

@media (max-width: 1100px) {
  .news-table th.col-summary,
  .news-table td.cell-summary {
    display: none;
  }
}

@media (max-width: 768px) {
  .dashboard {
    grid-template-columns: 1fr;
    grid-template-rows: var(--header-height) 1fr var(--statusbar-height);
  }

  .hamburger-btn {
    display: flex;
  }

  .sidebar {
    position: fixed;
    top: var(--header-height);
    left: 0;
    bottom: var(--statusbar-height);
    width: 280px;
    z-index: 30;
    transform: translateX(-100%);
    transition: transform var(--duration-slow) var(--ease-out);
    box-shadow: 4px 0 24px rgba(0, 0, 0, 0.3);
  }

  .sidebar.open {
    transform: translateX(0);
  }

  .sidebar-backdrop {
    position: fixed;
    inset: 0;
    top: var(--header-height);
    background: rgba(0, 0, 0, 0.5);
    z-index: 25;
    opacity: 0;
    pointer-events: none;
    transition: opacity var(--duration-slow);
  }

  .sidebar-backdrop.open {
    opacity: 1;
    pointer-events: auto;
  }

  .main {
    grid-column: 1;
  }

  .statusbar {
    grid-column: 1;
  }

  .news-table .col-source,
  .news-table .cell-source,
  .news-table .col-ticker,
  .news-table .cell-ticker,
  .news-table .col-confidence,
  .news-table .cell-confidence,
  .news-table .col-risk,
  .news-table .cell-risk,
  .news-table .col-tradeable,
  .news-table .cell-tradeable {
    display: none;
  }

  .header-stat.desktop-only {
    display: none;
  }

  .shortcuts-hint {
    display: none;
  }

  .statusbar-right {
    display: none;
  }
}

@media (max-width: 480px) {
  .news-table .col-sentiment,
  .news-table .cell-sentiment {
    display: none;
  }

  .cell-headline {
    font-size: 12px;
  }
}

/* =========================================================================
   Auth UI
   ========================================================================= */

.btn-signin {
  color: var(--green);
}

.btn-user {
  display: flex;
  align-items: center;
  gap: 6px;
}

.user-avatar {
  width: 20px;
  height: 20px;
  border-radius: 50%;
  border: 1px solid var(--border);
}

.user-name {
  max-width: 100px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.tier-badge {
  font-size: 9px;
  font-weight: 700;
  letter-spacing: 0.05em;
  padding: 1px 5px;
  border-radius: 3px;
  background: var(--bg-surface-3);
  color: var(--text-secondary);
  border: 1px solid var(--border);
}

.tier-badge.pro {
  background: rgba(56, 139, 253, 0.15);
  color: var(--blue);
  border-color: rgba(56, 139, 253, 0.3);
}

.user-menu {
  position: relative;
}

.user-dropdown {
  display: none;
  position: absolute;
  top: calc(100% + 4px);
  right: 0;
  min-width: 200px;
  background: var(--bg-surface);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 4px 0;
  z-index: 1000;
  box-shadow: 0 8px 24px rgba(0, 0, 0, 0.4);
}

.user-dropdown.open {
  display: block;
}

.user-dropdown-header {
  padding: 8px 12px;
  border-bottom: 1px solid var(--border);
  font-size: 11px;
  color: var(--text-secondary);
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.tier-label {
  font-weight: 600;
  color: var(--text-primary);
}

.user-dropdown-item {
  display: block;
  width: 100%;
  padding: 6px 12px;
  text-align: left;
  font-size: 12px;
  color: var(--text-primary);
  background: none;
  border: none;
  cursor: pointer;
  text-decoration: none;
  font-family: inherit;
}

.user-dropdown-item:hover {
  background: var(--bg-hover);
}

/* =========================================================================
   Column Settings
   ========================================================================= */

.column-settings-wrap {
  position: relative;
}

.column-settings-panel {
  display: none;
  position: absolute;
  top: calc(100% + 4px);
  right: 0;
  min-width: 220px;
  background: var(--bg-surface);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  z-index: 1000;
  box-shadow: 0 8px 24px rgba(0, 0, 0, 0.4);
  overflow: visible;
}

.column-settings-panel.open {
  display: block;
}

.col-settings-header {
  padding: 8px 12px;
  border-bottom: 1px solid var(--border);
  font-size: 10px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: var(--text-muted);
}

.col-settings-list {
  padding: 4px 0;
}

.col-toggle-item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 6px 12px;
  cursor: pointer;
  transition: background var(--duration-fast);
  user-select: none;
}

.col-toggle-item:hover {
  background: var(--bg-hover);
}

.col-toggle-item.locked {
  opacity: 0.5;
  cursor: not-allowed;
}

.col-toggle-item.locked:hover {
  background: transparent;
}

.col-toggle-item.required {
  opacity: 0.7;
}

.col-toggle-label {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 12px;
  color: var(--text-primary);
}

.col-lock-icon {
  color: var(--text-muted);
  flex-shrink: 0;
}

/* Toggle switch */
.col-toggle-switch {
  position: relative;
  display: inline-flex;
  align-items: center;
}

.col-toggle-switch input {
  position: absolute;
  opacity: 0;
  width: 0;
  height: 0;
}

.col-toggle-track {
  width: 32px;
  height: 18px;
  background: var(--bg-surface-3);
  border: 1px solid var(--border);
  border-radius: 9px;
  position: relative;
  transition: all var(--duration-fast);
  cursor: pointer;
}

.col-toggle-thumb {
  position: absolute;
  top: 2px;
  left: 2px;
  width: 12px;
  height: 12px;
  background: var(--text-muted);
  border-radius: 50%;
  transition: all var(--duration-fast);
}

.col-toggle-switch input:checked + .col-toggle-track {
  background: var(--blue-bg);
  border-color: var(--blue);
}

.col-toggle-switch input:checked + .col-toggle-track .col-toggle-thumb {
  transform: translateX(14px);
  background: var(--blue);
}

.col-toggle-switch.disabled {
  pointer-events: none;
}

.col-toggle-switch.disabled .col-toggle-track {
  opacity: 0.4;
}

/* Drag handle */
.col-drag-handle {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 20px;
  flex-shrink: 0;
  color: #7d8590;
  cursor: grab;
  font-size: 18px;
  font-weight: bold;
  line-height: 1;
  transition: color var(--duration-fast);
}

.col-toggle-item:hover .col-drag-handle {
  color: #f0f6fc;
}

.col-toggle-item.dragging {
  opacity: 0.4;
}

.col-toggle-item.drag-over-above {
  box-shadow: 0 -2px 0 0 var(--blue);
}

.col-toggle-item.drag-over-below {
  box-shadow: 0 2px 0 0 var(--blue);
}

/* Header column drag-and-drop reorder */
.news-table thead th[draggable] {
  cursor: grab;
}

.news-table thead th.th-dragging {
  opacity: 0.4;
}

.news-table thead th.th-drag-over-left {
  box-shadow: inset 3px 0 0 0 var(--blue);
}

.news-table thead th.th-drag-over-right {
  box-shadow: inset -3px 0 0 0 var(--blue);
}

/* =========================================================================
   Company Profile Modal
   ========================================================================= */

.company-profile-modal {
  width: min(560px, 90vw);
}

.company-profile-tabs {
  display: flex;
  gap: 0;
  padding: 0 var(--sp-4);
  border-bottom: 1px solid var(--border);
  background: var(--bg-surface);
}

.cp-tab {
  padding: var(--sp-2) var(--sp-4);
  font-family: 'JetBrains Mono', monospace;
  font-size: 11px;
  font-weight: 500;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.5px;
  border: none;
  background: none;
  cursor: pointer;
  position: relative;
  transition: color var(--duration-fast);
}

.cp-tab:hover {
  color: var(--text-secondary);
}

.cp-tab.active {
  color: var(--blue);
}

.cp-tab.active::after {
  content: '';
  position: absolute;
  bottom: -1px;
  left: 0;
  right: 0;
  height: 2px;
  background: var(--blue);
  border-radius: 1px 1px 0 0;
}

.company-profile-body {
  padding: var(--sp-4);
}

/* Loading skeleton */
.cp-loading-row {
  margin-bottom: var(--sp-2);
}

.cp-loading-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: var(--sp-3);
  margin-top: var(--sp-3);
}

/* Error state */
.cp-error {
  text-align: center;
  padding: var(--sp-4) 0;
  color: var(--text-secondary);
}

.cp-error-icon {
  width: 40px;
  height: 40px;
  border-radius: 50%;
  background: var(--red-bg);
  border: 1px solid var(--red-border);
  color: var(--red);
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: 700;
  font-size: 18px;
  margin: 0 auto var(--sp-3);
}

.cp-error p {
  font-size: 14px;
  font-weight: 600;
  color: var(--text-primary);
  margin-bottom: var(--sp-1);
}

.cp-error span {
  font-size: 12px;
  color: var(--text-muted);
}

/* Header with logo */
.cp-header {
  display: flex;
  align-items: center;
  gap: var(--sp-4);
  margin-bottom: var(--sp-4);
  padding-bottom: var(--sp-4);
  border-bottom: 1px solid var(--border-muted);
}

.cp-logo {
  width: 48px;
  height: 48px;
  border-radius: var(--radius-md);
  background: var(--bg-surface-2);
  object-fit: contain;
}

.cp-header-info {
  flex: 1;
  min-width: 0;
}

.cp-name {
  font-size: 18px;
  font-weight: 700;
  color: var(--text-primary);
  line-height: 1.3;
}

.cp-symbol-row {
  display: flex;
  align-items: center;
  gap: var(--sp-2);
  margin-top: var(--sp-1);
}

.cp-symbol {
  font-family: 'JetBrains Mono', monospace;
  font-size: 13px;
  font-weight: 600;
  color: var(--blue);
}

.cp-sector {
  font-size: 11px;
  color: var(--text-muted);
  padding: 1px 6px;
  background: var(--bg-surface-2);
  border: 1px solid var(--border-muted);
  border-radius: var(--radius-sm);
}

/* Metrics grid — reuses detail-metric from ticker recommendation */
.cp-metrics {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: var(--sp-3);
  margin-bottom: var(--sp-4);
}

/* Description */
.cp-description {
  margin-bottom: var(--sp-4);
}

.cp-desc-label {
  font-size: 10px;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-bottom: var(--sp-2);
}

.cp-desc-text {
  font-size: 13px;
  color: var(--text-secondary);
  line-height: 1.6;
  max-height: 120px;
  overflow-y: auto;
  overscroll-behavior: contain;
}

/* Homepage link */
.cp-links {
  padding-top: var(--sp-3);
  border-top: 1px solid var(--border-muted);
}

.cp-homepage {
  display: inline-flex;
  align-items: center;
  gap: var(--sp-1);
  font-size: 12px;
  color: var(--blue);
  text-decoration: none;
  transition: opacity var(--duration-fast);
}

.cp-homepage:hover {
  opacity: 0.8;
  text-decoration: underline;
}

/* No data state */
.cp-no-data {
  text-align: center;
  padding: var(--sp-8) var(--sp-4);
  color: var(--text-secondary);
}

.cp-no-data-icon {
  width: 40px;
  height: 40px;
  border-radius: 50%;
  background: var(--bg-surface-2);
  border: 1px solid var(--border);
  color: var(--text-muted);
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: 700;
  font-size: 18px;
  margin: 0 auto var(--sp-3);
}

.cp-no-data p {
  font-size: 14px;
  font-weight: 600;
  color: var(--text-primary);
  margin-bottom: var(--sp-1);
}

.cp-no-data span {
  font-size: 12px;
  color: var(--text-muted);
}

/* Financials tab */
.cp-fin-period {
  font-size: 11px;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-bottom: var(--sp-3);
}

.cp-fin-metrics {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: var(--sp-3);
  margin-bottom: var(--sp-4);
}

/* Earnings chart section */
.cp-fin-chart-section {
  padding-top: var(--sp-4);
  border-top: 1px solid var(--border-muted);
}

.cp-bar-chart {
  display: flex;
  align-items: flex-end;
  gap: var(--sp-3);
  padding: var(--sp-4) 0;
  min-height: 140px;
}

.cp-bar-col {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: var(--sp-1);
}

.cp-bar-value {
  font-family: 'JetBrains Mono', monospace;
  font-size: 11px;
  font-weight: 600;
}

.cp-bar-track {
  width: 100%;
  height: 80px;
  background: var(--bg-surface-2);
  border-radius: var(--radius-sm);
  position: relative;
  display: flex;
  align-items: flex-end;
  overflow: hidden;
}

.cp-bar-fill {
  width: 100%;
  border-radius: var(--radius-sm) var(--radius-sm) 0 0;
  transition: height var(--duration-slow) var(--ease-out);
  min-height: 2px;
}

.cp-bar-fill.cp-bar-positive,
.cp-bar-fill.cp-bar-beat {
  background: var(--green);
  opacity: 0.8;
}

.cp-bar-fill.cp-bar-negative,
.cp-bar-fill.cp-bar-miss {
  background: var(--red);
  opacity: 0.8;
}

.cp-bar-value.cp-bar-positive,
.cp-bar-value.cp-bar-beat {
  color: var(--green);
}

.cp-bar-value.cp-bar-negative,
.cp-bar-value.cp-bar-miss {
  color: var(--red);
}

.cp-bar-label {
  font-family: 'JetBrains Mono', monospace;
  font-size: 10px;
  color: var(--text-muted);
  text-transform: uppercase;
}

.cp-bar-est {
  font-size: 9px;
  color: var(--text-muted);
}

.cp-bar-legend {
  display: flex;
  gap: var(--sp-4);
  justify-content: center;
  padding-top: var(--sp-2);
}

.cp-legend-item {
  display: flex;
  align-items: center;
  gap: var(--sp-1);
  font-size: 10px;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.3px;
}

.cp-legend-dot {
  width: 8px;
  height: 8px;
  border-radius: 2px;
  display: inline-block;
}

.cp-legend-dot.cp-bar-positive {
  background: var(--green);
  opacity: 0.8;
}

.cp-legend-dot.cp-bar-negative {
  background: var(--red);
  opacity: 0.8;
}

/* Company Profile — Competitors Tab */
.cp-comp-section {
  padding: 4px 0;
}

.cp-comp-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 13px;
  margin-top: 8px;
}

.cp-comp-table th {
  text-align: left;
  color: var(--text-muted);
  font-weight: 500;
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  padding: 8px 10px;
  border-bottom: 1px solid var(--border);
}

.cp-comp-table td {
  padding: 10px;
  border-bottom: 1px solid var(--border-muted);
  color: var(--text-primary);
}

.cp-comp-row:hover {
  background: var(--bg-hover);
}

.cp-comp-ticker-link {
  color: var(--green);
  cursor: pointer;
  font-weight: 600;
  font-family: var(--font-mono, monospace);
}

.cp-comp-ticker-link:hover {
  text-decoration: underline;
}

.cp-comp-name {
  color: var(--text-secondary);
  max-width: 180px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.cp-comp-mcap,
.cp-comp-price {
  font-family: var(--font-mono, monospace);
  text-align: right;
}

.cp-comp-change {
  font-family: var(--font-mono, monospace);
  text-align: right;
}

.cp-comp-change.positive {
  color: var(--green);
}

.cp-comp-change.negative {
  color: var(--red);
}

.cp-comp-sector {
  color: var(--text-muted);
  font-size: 12px;
  max-width: 150px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

/* Make ticker badges look clickable */
.ticker-badge {
  cursor: pointer;
}

/* Company Profile — Institutions Tab */
.cp-inst-date-banner {
  background: var(--bg-hover);
  border: 1px solid var(--border);
  border-radius: var(--radius-md);
  padding: 10px 14px;
  font-size: 13px;
  font-weight: 600;
  color: var(--blue);
  margin-bottom: 12px;
  font-family: var(--font-mono, monospace);
}

.cp-inst-tooltip {
  display: flex;
  align-items: flex-start;
  gap: 10px;
  background: color-mix(in srgb, var(--blue) 8%, transparent);
  border: 1px solid color-mix(in srgb, var(--blue) 25%, transparent);
  border-radius: var(--radius-md);
  padding: 10px 14px;
  margin-bottom: 12px;
  font-size: 12px;
  line-height: 1.5;
  color: var(--text-secondary);
}

.cp-inst-tooltip-text {
  flex: 1;
}

.cp-inst-tooltip-text strong {
  color: var(--text-primary);
}

.cp-inst-tooltip-dismiss {
  background: none;
  border: none;
  color: var(--text-muted);
  cursor: pointer;
  font-size: 14px;
  padding: 0 4px;
  line-height: 1;
  flex-shrink: 0;
}

.cp-inst-tooltip-dismiss:hover {
  color: var(--text-primary);
}

.cp-inst-summary {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 12px;
  margin-bottom: 16px;
}

.cp-inst-summary-item {
  background: var(--bg-hover);
  border-radius: var(--radius-md);
  padding: 10px 14px;
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.cp-inst-summary-label {
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  color: var(--text-muted);
  font-weight: 500;
}

.cp-inst-summary-value {
  font-size: 16px;
  font-weight: 600;
  font-family: var(--font-mono, monospace);
  color: var(--text-primary);
}

.cp-inst-section {
  padding: 4px 0;
  margin-bottom: 16px;
}

.cp-inst-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 13px;
  margin-top: 8px;
}

.cp-inst-table th {
  text-align: left;
  color: var(--text-muted);
  font-weight: 500;
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  padding: 8px 10px;
  border-bottom: 1px solid var(--border);
}

.cp-inst-table td {
  padding: 10px;
  border-bottom: 1px solid var(--border-muted);
  color: var(--text-primary);
}

.cp-inst-row:hover {
  background: var(--bg-hover);
}

.cp-inst-name {
  max-width: 220px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.cp-inst-shares,
.cp-inst-value,
.cp-inst-pct {
  font-family: var(--font-mono, monospace);
  text-align: right;
}

.cp-inst-change {
  text-align: center;
  width: 60px;
}

.cp-inst-change-up {
  color: var(--green);
}

.cp-inst-change-down {
  color: var(--red);
}

.cp-inst-change-flat {
  color: var(--text-muted);
}

.cp-inst-badge {
  display: inline-block;
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.5px;
  padding: 2px 6px;
  border-radius: 3px;
  vertical-align: middle;
}

.cp-inst-badge-new {
  background: color-mix(in srgb, var(--green) 15%, transparent);
  color: var(--green);
}

.cp-inst-13d {
  border-left: 3px solid var(--red);
}

.cp-inst-13g {
  border-left: 3px solid var(--green);
}

.cp-inst-filer {
  max-width: 200px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.cp-inst-filing-date {
  font-family: var(--font-mono, monospace);
  white-space: nowrap;
}

.cp-inst-filing-type {
  font-size: 12px;
  color: var(--text-muted);
  white-space: nowrap;
}

.cp-inst-source {
  margin-top: 16px;
  padding-top: 12px;
  border-top: 1px solid var(--border-muted);
  font-size: 11px;
  color: var(--text-muted);
  text-align: center;
}

/* =========================================================================
   Reduced motion
   ========================================================================= */

@media (prefers-reduced-motion: reduce) {
  *, *::before, *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }

  .status-dot.connected::after {
    animation: none;
  }
}

